package com.babidndn.cart;
import com.babidndn.common.NotFoundException;import com.babidndn.menu.*;import org.springframework.stereotype.Service;import java.util.List;
@Service public class CartService { private final CartItemRepository carts; private final MenuRepository menus; public CartService(CartItemRepository carts,MenuRepository menus){this.carts=carts;this.menus=menus;} public List<CartItem> findAll(){return carts.findAll();} public CartItem add(CartItemRequest r){Menu m=menus.findById(r.menuId()).orElseThrow(()->new NotFoundException("menu not found")); if(m.isSoldOut()) throw new IllegalArgumentException("sold out menu"); return carts.save(new CartItem(m,r.quantity(),r.optionSummary(),r.optionPrice()));} public CartItem update(Long id,CartItemRequest r){CartItem item=carts.findById(id).orElseThrow(()->new NotFoundException("cart item not found")); item.update(r.quantity(),r.optionSummary(),r.optionPrice()); return carts.save(item);} public void delete(Long id){carts.deleteById(id);} public void clear(){carts.deleteAll();} }
